int lifoNestedExit(int mode) {
    int trace = 0;
    defer { trace = trace * 10 + 1; };

    if (mode > 0) {
        defer { trace = trace * 10 + 2; };

        if (mode > 1) {
            defer { trace = trace * 10 + 3; };
            // Exiting here should run 3, then 2, then 1.
            return trace;
        }

        // Exiting here should run 2, then 1.
        return trace;
    }

    // Exiting here should run only 1.
    return trace;
}
